function Btn({ href, variant, children, onClick, target, rel }) {
  const s = { green:{background:T.accent,color:"#fff",border:"none"}, ghostLight:{background:"transparent",color:"#fff",border:"1.5px solid rgba(255,255,255,0.35)"}, outlineGreen:{background:"transparent",color:T.accent,border:`1.5px solid ${T.accent}`} }[variant] || {background:T.accent,color:"#fff",border:"none"};
  const handleClick = (e) => {
    if (href && href.startsWith('#')) {
      e.preventDefault();
      const target = document.querySelector(href);
      if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
    if (onClick) onClick(e);
  };
  return (
    <a href={href} target={target} rel={rel} onClick={handleClick} style={{ display:"inline-flex", alignItems:"center", gap:8, padding:"11px 24px", borderRadius:50, fontSize:14, fontWeight:600, cursor:"pointer", letterSpacing:"-0.01em", transition:"all 0.2s ease", ...s }}
      onMouseEnter={e=>{e.currentTarget.style.opacity="0.85";e.currentTarget.style.transform="translateY(-1px)"}}
      onMouseLeave={e=>{e.currentTarget.style.opacity="1";e.currentTarget.style.transform="none"}}>
      {children}
    </a>
  );
}

/* ── VIEW COUNTER HOOK ── */
function useViewCounter() {
  const [totalViews, setTotalViews] = useState(null);
  const [viewData, setViewData] = useState({ daily: [], monthly: [], yearly: [] });

  useEffect(() => {
    const today = new Date();
    const dayKey = today.toISOString().split('T')[0];
    const monthKey = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}`;
    const yearKey = `${today.getFullYear()}`;
    const uniqueKey = 'portfolio-unique-viewer';
    const localTotalKey = 'portfolio-local-total';
    const alreadyViewed = localStorage.getItem(uniqueKey);

    console.log('View counter: unique viewer?', Boolean(alreadyViewed), 'uniqueKey:', uniqueKey);

    if (!alreadyViewed) {
      incrementPortfolioViews(dayKey, monthKey, yearKey)
        .then((data) => {
          if (data) {
            localStorage.setItem(uniqueKey, '1');
            setViewDataFromSnapshot(data);
          } else {
            const fallback = { daily: { [dayKey]: 1 }, monthly: { [monthKey]: 1 }, yearly: { [yearKey]: 1 }, total: 1, lastVisit: dayKey };
            localStorage.setItem(uniqueKey, '1');
            localStorage.setItem(localTotalKey, '1');
            setViewDataFromSnapshot(fallback);
          }
        })
        .catch(() => {
          const fallback = { daily: { [dayKey]: 1 }, monthly: { [monthKey]: 1 }, yearly: { [yearKey]: 1 }, total: 1, lastVisit: dayKey };
          localStorage.setItem(uniqueKey, '1');
          localStorage.setItem(localTotalKey, '1');
          setViewDataFromSnapshot(fallback);
        });
    } else {
      getPortfolioViews().then((data) => {
        if (data) setViewDataFromSnapshot(data);
        else {
          const localTotal = Number(localStorage.getItem(localTotalKey) || 1);
          setViewDataFromSnapshot({ daily: { [dayKey]: localTotal }, monthly: { [monthKey]: localTotal }, yearly: { [yearKey]: localTotal }, total: localTotal, lastVisit: dayKey });
        }
      });
    }
  }, []);

  const setViewDataFromSnapshot = (data) => {
    const today = new Date();

    const last14Days = [];
    for (let i = 13; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - i);
      const k = d.toISOString().split('T')[0];
      last14Days.push({ label: k.slice(5), value: data.daily?.[k] || 0 });
    }

    const last12Months = [];
    for (let i = 11; i >= 0; i--) {
      const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
      const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
      last12Months.push({ label: k.slice(5), value: data.monthly?.[k] || 0 });
    }

    const years = [];
    for (let y = 2025; y <= today.getFullYear(); y++) {
      years.push({ label: `${y}`, value: data.yearly?.[`${y}`] || 0 });
    }

    setTotalViews(data.total || 0);
    setViewData({ daily: last14Days, monthly: last12Months, yearly: years });
  };

  return { totalViews, viewData };
}

/* ── MINI BAR CHART ── */
function MiniBarChart({ data, color }) {
  if (!data || data.length === 0) return null;
  const max = Math.max(...data.map(d => d.value), 1);
  const showEvery = data.length > 8 ? Math.ceil(data.length / 7) : 1;
  return (
    <div style={{ display:'flex', alignItems:'flex-end', gap:3, height:80, width:'100%' }}>
      {data.map((d, i) => (
        <div key={i} style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:3, height:'100%', justifyContent:'flex-end' }}>
          <div style={{ width:'100%', background: color, borderRadius:'3px 3px 0 0', height:`${Math.max((d.value/max)*70, d.value>0?4:1)}px`, transition:'height 0.4s ease', opacity: d.value===0 ? 0.2 : 1 }} title={`${d.value} views`}/>
          {(i % showEvery === 0) && <div style={{ fontSize:8, color:'rgba(255,255,255,0.4)', transform:'rotate(-40deg)', whiteSpace:'nowrap', marginTop:2 }}>{d.label}</div>}
        </div>
      ))}
    </div>
  );
}

